import type React from 'react';
/**
 * refObject 延迟获取元素方法
 */
export type RefThunkElement<T> = React.RefObject<T> | React.MutableRefObject<T | null>;
/**
 * callback 延迟获取元素方法
 */
export type CallbackThunkElement<T> = () => T | null;
/**
 * 延迟获取元素方法，可以是 refObject，callback，query，element
 */
export type ThunkElement<T> = string | T | null | CallbackThunkElement<T> | RefThunkElement<T>;
export declare const getThunkElement: <T extends object>(container: ThunkElement<T>) => any;
